//! Unified mesh spectrometer rows + knot-shadow sidecar payloads.
//!
//! **Track A** — operational JSON-lines records for correlating residuals, mesh runs,
//! and benchmarks ([`SpectrometerMeshRow`]).
//!
//! **Track B** — versioned combinatorial shadows aligned to `open-source/gnosis-math`
//! `KhovanovCategorifiesJones` / `BridgeKhovanovRT3D` witness integers ([`KnotShadowV1`],
//! [`knot_shadow::QMinusOneWitness`]).
//!
//! See `TOPOLOGICAL_SPECTROMETER_DUAL_TRACK.md` at the crate root.

pub mod knot_shadow {
    //! Sidecar schema + frozen integers matching Lean `native_decide` galleries.

    use serde::{Deserialize, Serialize};

    /// Container version string (JSON `schema_version` field).
    pub const SCHEMA_VERSION: &str = "gnosis.knot-shadow.v1";

    /// Kauffman-resolution table + crossing metadata (Bar–Natan style).
    #[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
    pub struct KnotShadowV1 {
        pub schema_version: String,
        /// Optional human label (e.g. `"unknot"`, `"trefoilPlus"`).
        pub diagram_label: Option<String>,
        pub n_plus: u32,
        pub n_minus: u32,
        /// Rows `( |α|, k(α) )` in the same order as `KhovanovCategorifiesJones.Diagram`.
        pub resolutions: Vec<[u32; 2]>,
    }

    impl KnotShadowV1 {
        pub fn new(
            diagram_label: Option<String>,
            n_plus: u32,
            n_minus: u32,
            resolutions: Vec<[u32; 2]>,
        ) -> Self {
            Self {
                schema_version: SCHEMA_VERSION.to_owned(),
                diagram_label,
                n_plus,
                n_minus,
                resolutions,
            }
        }

        #[must_use]
        pub fn unknot_standard() -> Self {
            KnotShadowV1::new(Some("unknot".to_owned()), 0, 0, vec![[0, 1]])
        }
    }

    /// Integer witnesses at **`q = -1`** (`bracket` / `jones_poly` in the Khovanov file),
    /// mirrored from **`BridgeKhovanovRT3D`** / `KhovanovCategorifiesJones`.
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub struct QMinusOneWitness {
        pub bracket_eval: i64,
        pub jones_shift_eval: i64,
        /// `ReshetikhinTuraev3DTQFT.jonesAtMinusOne` row when defined.
        pub rt_jones_tab: Option<i64>,
    }

    impl QMinusOneWitness {
        pub const UNKNOT: Self = Self {
            bracket_eval: -2,
            jones_shift_eval: -2,
            rt_jones_tab: Some(-2),
        };
        pub const HOPF_PLUS: Self = Self {
            bracket_eval: 4,
            jones_shift_eval: 4,
            rt_jones_tab: Some(-4),
        };
        pub const TREFOIL_PLUS: Self = Self {
            bracket_eval: 2,
            jones_shift_eval: -2,
            rt_jones_tab: Some(-6),
        };
        pub const FIGURE_EIGHT: Self = Self {
            bracket_eval: -8,
            jones_shift_eval: -8,
            rt_jones_tab: Some(-10),
        };
    }

    #[cfg(test)]
    mod tests {
        use super::*;

        #[test]
        fn unknot_payload_round_trips() {
            let k = KnotShadowV1::unknot_standard();
            let json = serde_json::to_string(&k).expect("serde");
            let back: KnotShadowV1 = serde_json::from_str(&json).expect("de");
            assert_eq!(k, back);
            assert_eq!(k.schema_version, SCHEMA_VERSION);
        }

        #[test]
        fn witness_table_matches_lean_gallery() {
            assert_eq!(QMinusOneWitness::UNKNOT.bracket_eval, -2);
            assert_eq!(QMinusOneWitness::UNKNOT.jones_shift_eval, -2);
            assert_eq!(QMinusOneWitness::HOPF_PLUS.bracket_eval, 4);
            assert_eq!(QMinusOneWitness::TREFOIL_PLUS.bracket_eval, 2);
            assert_eq!(QMinusOneWitness::TREFOIL_PLUS.jones_shift_eval, -2);
            assert_eq!(QMinusOneWitness::FIGURE_EIGHT.bracket_eval, -8);
            assert_eq!(QMinusOneWitness::FIGURE_EIGHT.rt_jones_tab, Some(-10));
        }
    }
}

use serde::{Deserialize, Serialize};
#[cfg(not(target_arch = "wasm32"))]
use std::sync::{
    atomic::{AtomicI8, Ordering},
    Mutex, OnceLock,
};

/// JSON row schema (`gnosis.mesh-spectrometer.v1`).
pub const MESH_SCHEMA_VERSION: &str = "gnosis.mesh-spectrometer.v1";

/// Operational flags for Pair X seeding and amplituhedron replay (Death #2 / #4).
/// Env: `GNOSIS_MESH_SPECTROMETER_PAIR_X_SEEDED`, `GNOSIS_MESH_SPECTROMETER_AMPLITUHEDRON_REPLAY_HIT`.
/// Programmatic: [`install_spectrometer_lane_flags`]; merge order: [`spectrometer_lane_flags_effective`]
/// (native only).
#[derive(Clone, Copy, Debug, Default, Eq, PartialEq)]
pub struct SpectrometerLaneFlags {
    pub pair_x_seeded: Option<bool>,
    pub amplituhedron_replay_hit: Option<bool>,
}

impl SpectrometerLaneFlags {
    /// Merge lane facts: fields that are `Some` in `over` replace `self`; otherwise keep `self`.
    pub fn overlay(self, over: SpectrometerLaneFlags) -> SpectrometerLaneFlags {
        SpectrometerLaneFlags {
            pair_x_seeded: over.pair_x_seeded.or(self.pair_x_seeded),
            amplituhedron_replay_hit: over
                .amplituhedron_replay_hit
                .or(self.amplituhedron_replay_hit),
        }
    }

    #[cfg(not(target_arch = "wasm32"))]
    fn from_env_relaxed() -> Self {
        SpectrometerLaneFlags {
            pair_x_seeded: parse_env_opt_bool("GNOSIS_MESH_SPECTROMETER_PAIR_X_SEEDED"),
            amplituhedron_replay_hit: parse_env_opt_bool(
                "GNOSIS_MESH_SPECTROMETER_AMPLITUHEDRON_REPLAY_HIT",
            ),
        }
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn parse_env_opt_bool(key: &str) -> Option<bool> {
    let raw = std::env::var_os(key)?;
    let s = raw.to_str()?.trim();
    if s.is_empty() {
        return None;
    }
    match s.to_ascii_lowercase().as_str() {
        "1" | "true" | "yes" | "on" => Some(true),
        "0" | "false" | "no" | "off" => Some(false),
        _ => None,
    }
}

#[cfg(not(target_arch = "wasm32"))]
static LANE_FLAGS_FROM_ENV: OnceLock<SpectrometerLaneFlags> = OnceLock::new();

#[cfg(not(target_arch = "wasm32"))]
static LANE_FLAGS_OVERRIDE: Mutex<Option<SpectrometerLaneFlags>> = Mutex::new(None);

/// Cached env (`GNOSIS_MESH_SPECTROMETER_PAIR_X_SEEDED`, `GNOSIS_MESH_SPECTROMETER_AMPLITUHEDRON_REPLAY_HIT`)
/// merged with any install from [`install_spectrometer_lane_flags`] (install wins per field when `Some`).
/// JSONL emission then overlays [`take_amplituhedron_replay_hint_overlay`] (kernel Death #2 hit, consumed once).
#[cfg(not(target_arch = "wasm32"))]
pub fn spectrometer_lane_flags_effective() -> SpectrometerLaneFlags {
    let base = *LANE_FLAGS_FROM_ENV.get_or_init(SpectrometerLaneFlags::from_env_relaxed);
    let Ok(lock) = LANE_FLAGS_OVERRIDE.lock() else {
        return base;
    };
    match *lock {
        Some(over) => base.overlay(over),
        None => base,
    }
}

/// Install process-wide lane flags for spectrometer rows (native).
/// Pass `None` to clear overrides and fall back to env only.
/// Mesh benches call this at run start/end so rows match Pair X / replay probes.
#[cfg(not(target_arch = "wasm32"))]
pub fn install_spectrometer_lane_flags(flags: Option<SpectrometerLaneFlags>) {
    let mut g = LANE_FLAGS_OVERRIDE
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    *g = flags;
}

// -1 = unset, 0 = false, 1 = true — consumed on next spectrometer JSONL row (swap).
#[cfg(not(target_arch = "wasm32"))]
static RUNTIME_AMPLITUHEDRON_REPLAY_HINT: AtomicI8 = AtomicI8::new(-1);

/// Record Death #2 replay outcome for the **next** mesh spectrometer row (native).
/// Values are **sticky** until the next JSONL append calls [`take_amplituhedron_replay_hint_overlay`]
/// (typically via `try_append_mesh_spectrometer_row_for_residual`). Wasm: no-op.
#[cfg(not(target_arch = "wasm32"))]
pub fn hint_amplituhedron_replay_hit(hit: Option<bool>) {
    match hit {
        None => RUNTIME_AMPLITUHEDRON_REPLAY_HINT.store(-1, Ordering::Relaxed),
        Some(false) => RUNTIME_AMPLITUHEDRON_REPLAY_HINT.store(0, Ordering::Relaxed),
        Some(true) => RUNTIME_AMPLITUHEDRON_REPLAY_HINT.store(1, Ordering::Relaxed),
    }
}

#[cfg(target_arch = "wasm32")]
#[inline]
pub fn hint_amplituhedron_replay_hit(_hit: Option<bool>) {}

#[cfg(not(target_arch = "wasm32"))]
pub(crate) fn take_amplituhedron_replay_hint_overlay() -> SpectrometerLaneFlags {
    match RUNTIME_AMPLITUHEDRON_REPLAY_HINT.swap(-1, Ordering::Relaxed) {
        0 => SpectrometerLaneFlags {
            amplituhedron_replay_hit: Some(false),
            pair_x_seeded: None,
        },
        1 => SpectrometerLaneFlags {
            amplituhedron_replay_hit: Some(true),
            pair_x_seeded: None,
        },
        _ => SpectrometerLaneFlags::default(),
    }
}

/// One correlate-able row from mesh runs (Pair X, residuals, benchmarks).
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct SpectrometerMeshRow {
    pub schema_version: String,
    /// Stable id for correlating Track A with Track B payloads.
    pub experiment_id: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub wall_clock_ms_unix: Option<u128>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub layer_idx: Option<u32>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub residual_capture_seq: Option<u32>,
    /// Optional L2 shorthand from offline analytics.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub residual_l2_sum_sq: Option<f64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub pair_x_seeded: Option<bool>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub amplituhedron_replay_hit: Option<bool>,
}

impl SpectrometerMeshRow {
    pub fn new_stub(experiment_id: impl Into<String>) -> Self {
        Self {
            schema_version: MESH_SCHEMA_VERSION.to_owned(),
            experiment_id: experiment_id.into(),
            wall_clock_ms_unix: None,
            layer_idx: None,
            residual_capture_seq: None,
            residual_l2_sum_sq: None,
            pair_x_seeded: None,
            amplituhedron_replay_hit: None,
        }
    }
}

/// Append one JSON line to a file (**native** only). Skips on wasm32 (not compiled).
///
/// Serialized with a process-wide lock so concurrent [`crate::residual_capture::capture_residual`]
/// calls cannot interleave JSON line bytes.
#[cfg(not(target_arch = "wasm32"))]
pub fn append_mesh_spectrometer_jsonl(
    path: &std::path::Path,
    row: &SpectrometerMeshRow,
) -> std::io::Result<()> {
    use std::fs::OpenOptions;
    use std::io::Write;
    use std::sync::Mutex;
    static WRITE_LOCK: Mutex<()> = Mutex::new(());
    let _guard = WRITE_LOCK.lock().unwrap_or_else(|p| p.into_inner());
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let mut f = OpenOptions::new().create(true).append(true).open(path)?;
    let line = serde_json::to_string(row).map_err(|e| {
        std::io::Error::new(std::io::ErrorKind::InvalidData, format!("serde_json: {e}"))
    })?;
    writeln!(f, "{line}")?;
    f.flush()?;
    Ok(())
}

#[cfg(test)]
mod mesh_row_tests {
    use super::*;

    #[cfg(not(target_arch = "wasm32"))]
    #[test]
    fn replay_hint_take_consumes_once() {
        hint_amplituhedron_replay_hit(Some(true));
        let t = take_amplituhedron_replay_hint_overlay();
        assert_eq!(t.amplituhedron_replay_hit, Some(true));
        let t2 = take_amplituhedron_replay_hint_overlay();
        assert_eq!(t2, SpectrometerLaneFlags::default());
    }

    #[test]
    fn lane_flags_overlay_fills_some_fields() {
        let base = SpectrometerLaneFlags {
            pair_x_seeded: Some(false),
            amplituhedron_replay_hit: None,
        };
        let over = SpectrometerLaneFlags {
            pair_x_seeded: None,
            amplituhedron_replay_hit: Some(true),
        };
        let m = base.overlay(over);
        assert_eq!(m.pair_x_seeded, Some(false));
        assert_eq!(m.amplituhedron_replay_hit, Some(true));

        let base2 = SpectrometerLaneFlags {
            pair_x_seeded: Some(false),
            amplituhedron_replay_hit: Some(false),
        };
        let over2 = SpectrometerLaneFlags {
            pair_x_seeded: Some(true),
            amplituhedron_replay_hit: None,
        };
        let m2 = base2.overlay(over2);
        assert_eq!(m2.pair_x_seeded, Some(true));
        assert_eq!(m2.amplituhedron_replay_hit, Some(false));
    }

    #[test]
    fn mesh_row_serializes() {
        let row = SpectrometerMeshRow {
            schema_version: MESH_SCHEMA_VERSION.to_owned(),
            experiment_id: "bench-42".to_owned(),
            wall_clock_ms_unix: Some(1_700_000_000_000),
            layer_idx: Some(7),
            residual_capture_seq: Some(3),
            residual_l2_sum_sq: Some(0.25),
            pair_x_seeded: Some(true),
            amplituhedron_replay_hit: Some(false),
        };
        let s = serde_json::to_string(&row).expect("json");
        let back: SpectrometerMeshRow = serde_json::from_str(&s).expect("de");
        assert_eq!(row, back);
    }
}
